import React from "react";
import { useNavigate } from "react-router-dom";
import "../styles/Signup.css";
import illustration from "../assets/signup-illustration.png";
// If you want video instead, import video
// import illustrationVideo from "../assets/signup-video.mp4";

function Signup() {
  const navigate = useNavigate();

  return (
    <div className="auth-container">
      <div className="auth-inner">

        {/* ===== SIGNUP CARD ===== */}
        <div className="auth-card">
          <h2>Create Account</h2>
          <p className="subtitle">Your AI therapist is waiting for you</p>

          <div className="form-grid">
            <input type="text" placeholder="Full Name" />

            <input type="email" placeholder="Email" />

            <select>
              <option value="">Select Gender</option>
              <option>Male</option>
              <option>Female</option>
              <option>Other</option>
            </select>

            <input type="date" />

            <input type="text" placeholder="Username" />

            <input type="password" placeholder="Password" />

            <input type="tel" placeholder="Phone Number" />

            <input type="tel" placeholder="Alternative Phone Number" />
          </div>

          <button>Sign Up</button>

          <p className="switch-text">
            Already have an account?{" "}
            <span onClick={() => navigate("/")}>Login</span>
          </p>
        </div>

        {/* ===== ANIMATED ILLUSTRATION ===== */}
        <div className="auth-illustration">
          <img src={illustration} alt="AI Therapist" />

          {/*
          // VIDEO VERSION (optional)
          <video
            src={illustrationVideo}
            autoPlay
            loop
            muted
          />
          */}
        </div>

      </div>
    </div>
  );
}

export default Signup;
